// Solution
function solve(config) {
  // Parse the config string
  const configLines = config.split('\n');
  // Initialize a flag to indicate whether the port mappings are valid
  let isValid = true;

  // Iterate over each line to extract the port mappings
  for (let line of configLines) {
    // Check if the line is a port mapping
    if (line.trim().startsWith('ports:')) {
      // Extract the host and exposed ports
      const [hostPort, exposedPort] = line.trim().split(':');

      // Check if the exposed port is within the valid range
      if (Number(exposedPort) >= 1024 && Number(exposedPort) <= 65535) {
        // Check if the exposed port is not equal to the host port
        if (Number(exposedPort) === Number(hostPort)) {
          isValid = false;
          break;
        }
      } else {
        isValid = false;
        break;
      }
    }
  }

  return isValid;
}

// Read input from stdin
const readline = require('readline').createInterface({
  input: process.stdin,
  output: process.stdout
});

// Read the config string from stdin
readline.on('line', (config) => {
  // Call the solve function with the config string
  const isValid = solve(config);
  // Print the result to stdout
  console.log(isValid);
});
